mapper.select:
SELECT sell_info.attr as auxiliaryAttribute, sell_info.nums as quantity, sell_info.discount as discountAmount, sell_info.tat as taxAmount, sell_info.tpt as totalAmountWithTax, goods.name as productName, goods.number as productNumber, goods.spec as specificationModel, goods.buy as cost, (goods.buy * sell_info.nums) as totalCost, sell_info.unit, sell_info.price, (sell_info.tpt - (goods.buy * sell_info.nums)) as grossProfit, CASE WHEN sell_info.tpt > 0 THEN (sell_info.tpt - (goods.buy * sell_info.nums)) / sell_info.tpt ELSE 0 END as grossProfitMargin FROM sell_info INNER JOIN sell ON sell_info.pid = sell.id INNER JOIN goods ON sell_info.goods = goods.id WHERE sell.examine=1
AND goods.name LIKE CONCAT('%', #{query.productName}, '%')
AND goods.number LIKE CONCAT('%', #{query.productNumber}, '%')
AND sell.time >= #{query.begintime}
AND sell.time <= #{query.endtime}
ORDER BY (sell_info.price * sell_info.nums) DESC

