AND goods.name LIKE CONCAT('%', #{query.productName}, '%')
AND goods.number LIKE CONCAT('%', #{query.productNumber}, '%')
AND sell.time >= #{query.begintime}
AND sell.time <= #{query.endtime}
ORDER BY (sell_info.price * sell_info.nums) DESC
